import { Tip } from "../types/tips";

function shuffleArray<T>(arr: T[]): T[] {
  const a = [...arr];
  for (let i = a.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [a[i], a[j]] = [a[j], a[i]];
  }
  return a;
}

export const tips: Tip[] = shuffleArray([
  // ── Coding Tips ──────────────────────────────────────────────
  { id: "ct-01", category: "Coding Tips", title: "VS Code shortcuts everyone should know", icon: "Terminal", content: "Mastering VS Code shortcuts like Ctrl+Shift+P for the command palette, Ctrl+D for multi-cursor selection, and Ctrl+` for the integrated terminal can save hours each week. Learn the most-used shortcuts one at a time rather than trying to memorize them all at once. Customize your keybindings.json for actions you repeat most frequently." },
  { id: "ct-02", category: "Coding Tips", title: "JavaScript tricks", icon: "Braces", content: "Use optional chaining (?.) and nullish coalescing (??) to write cleaner conditional logic without nested ternary operators. Array methods like map(), filter(), and reduce() make data transformations more readable than traditional for loops. Destructuring assignments and spread operators simplify working with objects and arrays." },
  { id: "ct-03", category: "Coding Tips", title: "React performance tips", icon: "Atom", content: "Memoize expensive computations with useMemo and useCallback to prevent unnecessary re-renders in React. Lazy load components with React.lazy and Suspense to reduce the initial bundle size. Keep state as local as possible and lift it only when truly needed by sibling components." },
  { id: "ct-04", category: "Coding Tips", title: "Node.js best practices", icon: "Server", content: "Use environment variables with dotenv to keep configuration separate from application code. Implement proper error handling with centralized error middleware instead of try-catch blocks everywhere. Leverage async/await with Promise.allSettled for concurrent independent operations." },
  { id: "ct-05", category: "Coding Tips", title: "Git commands you'll actually use", icon: "GitBranch", content: "Master git commit --amend to fix the last commit message or add staged changes without creating a new commit. Use git log --oneline --graph --decorate to visualize branch history clearly. Git stash pop and git stash apply let you temporarily save work in progress." },
  { id: "ct-06", category: "Coding Tips", title: "CSS tricks", icon: "PaintBucket", content: "Use CSS Grid for two-dimensional layouts and Flexbox for one-dimensional arrangements to create responsive designs effortlessly. The clamp() function lets you set fluid font sizes that scale between minimum and maximum values. CSS custom properties (variables) make themes and design tokens much easier to manage." },
  { id: "ct-07", category: "Coding Tips", title: "SQL optimization tips", icon: "Database", content: "Add indexes on columns used frequently in WHERE clauses and JOIN conditions to dramatically speed up queries. Use EXPLAIN ANALYZE to understand how PostgreSQL executes your queries and identify bottlenecks. Avoid SELECT * and fetch only the columns you actually need." },
  { id: "ct-08", category: "Coding Tips", title: "Regex cheat sheet", icon: "Regex", content: "Use regex101.com with the PCRE2 flavor to test and debug your patterns interactively. Character classes like \\d, \\w, and \\s simplify matching digits, word characters, and whitespace. Capture groups with (?<name>...) make extracted data easier to reference by name rather than index." },
  { id: "ct-09", category: "Coding Tips", title: "Debugging techniques", icon: "Bug", content: "Use console.table() instead of console.log() to display arrays of objects in a readable table format. Debugger statements combined with browser DevTools breakpoints give you full control over step-through debugging. The Network tab shows waterfall timings that reveal slow API calls or large assets." },
  { id: "ct-10", category: "Coding Tips", title: "Common programming mistakes", icon: "AlertTriangle", content: "Comparing floats with == or === often fails due to floating-point precision; use a tolerance-based comparison like Math.abs(a - b) < 1e-10 instead. Mutating function parameters directly can cause hard-to-trace side effects — treat all parameters as immutable when possible. Off-by-one errors in loops are best caught by using inclusive vs exclusive boundary checks explicitly." },
  { id: "ct-11", category: "Coding Tips", title: "Clean code principles", icon: "Sparkles", content: "Name functions and variables for what they do, not how they do it — a function called getUserData is better than fetchAndParseUserJSON. Keep functions small and focused on a single responsibility so they can be tested and reused independently. Avoid magic numbers by extracting them into named constants with clear intent." },
  { id: "ct-12", category: "Coding Tips", title: "API design tips", icon: "Plug", content: "Design APIs around resources (nouns) rather than actions (verbs) using consistent plural naming like /users instead of /getUsers. Return proper HTTP status codes — 201 for creation, 204 for successful deletions, and 422 for validation errors. Version your API from day one with a simple prefix like /v1/ to avoid breaking existing clients." },
  { id: "ct-13", category: "Coding Tips", title: "Security best practices", icon: "ShieldCheck", content: "Always validate and sanitize user input on the server side — never rely solely on client-side validation for security. Hash passwords with bcrypt or Argon2 instead of using fast algorithms like SHA-256. Keep dependencies updated and use npm audit or Dependabot to catch known vulnerabilities early." },
  { id: "ct-14", category: "Coding Tips", title: "Docker shortcuts", icon: "Container", content: "Use .dockerignore to exclude node_modules and other large directories from the Docker build context to speed up builds. Layer caching works best when you copy package.json and install dependencies before copying source code. Multi-stage builds let you compile in one stage and copy only the binary to the final minimal image." },
  { id: "ct-15", category: "Coding Tips", title: "Linux terminal commands", icon: "TerminalSquare", content: "Learn to navigate the terminal with Ctrl+A (beginning of line), Ctrl+E (end), Ctrl+U (clear line), and Ctrl+W (delete word backward). Use the history command combined with grep to quickly find previously run commands. Pipes (|), redirections (> and >>), and chaining with && make terminal workflows far more powerful." },
  { id: "ct-16", category: "Coding Tips", title: "Keyboard shortcuts for developers", icon: "Keyboard", content: "Ctrl+Shift+K deletes the current line in VS Code, while Alt+Up/Down moves lines around without cut-paste. Mastering your IDE's multi-cursor feature (Alt+Click) lets you edit multiple occurrences simultaneously. Learning OS-level shortcuts like Win+Arrow for window snapping and Alt+Tab for quick switching pays dividends." },
  { id: "ct-17", category: "Coding Tips", title: "Browser DevTools tips", icon: "Inspect", content: "The Elements panel lets you live-edit HTML and CSS to prototype layout changes before writing code. The Console supports $0 to reference the currently selected DOM element and $_ for the last evaluated result. Performance tab recordings show you exactly where JavaScript execution and layout recalculations are taking too long." },
  { id: "ct-18", category: "Coding Tips", title: "AI prompts for developers", icon: "BrainCircuit", content: "Be specific about context, role, and constraints when crafting prompts — 'Act as a senior React developer reviewing my code' yields better results than a vague request. Provide examples of the output format you expect to guide the model toward your desired response. Iterate by feeding the AI's output back as refined prompts to converge on the solution." },
  { id: "ct-19", category: "Coding Tips", title: "Code review checklist", icon: "ClipboardCheck", content: "Check that the code solves the actual problem described in the PR description and not an edge case that doesn't exist. Look for hardcoded values, missing error handling, and unclear variable names that will confuse future maintainers. Verify that automated tests cover the happy path, error paths, and at least one boundary condition." },
  { id: "ct-20", category: "Coding Tips", title: "Accessibility checklist", icon: "Eye", content: "All images must include descriptive alt text so screen readers can convey their meaning to visually impaired users. Ensure all interactive elements are keyboard-navigable by testing with Tab, Enter, and Escape alone. Color contrast ratios should meet WCAG AA standards — use tools like axe DevTools to audit your pages." },

  // ── Productivity ──────────────────────────────────────────────
  { id: "pr-01", category: "🚀 Productivity", title: "Pomodoro techniques", icon: "Timer", content: "Work in focused 25-minute intervals followed by 5-minute breaks to maintain high concentration without burnout. After four pomodoros, take a longer 15-30 minute break to reset your mental energy. Use a physical timer or dedicated app to enforce the cycle without distractions." },
  { id: "pr-02", category: "🚀 Productivity", title: "Deep work methods", icon: "Focus", content: "Schedule 90-120 minute blocks for deep work during your peak energy hours, typically morning for most people. Eliminate all notifications, close Slack and email, and put your phone out of sight before starting. Track your deep work hours each week and gradually increase them to build the mental muscle." },
  { id: "pr-03", category: "🚀 Productivity", title: "Avoiding burnout", icon: "Flame", content: "Set a hard stop time for work each day and guard it as strictly as a meeting with a client. Take at least one full day off per week where you do not check work messages or open your code editor. Incorporate micro-breaks every 90 minutes — a short walk or stretching prevents cumulative mental fatigue." },
  { id: "pr-04", category: "🚀 Productivity", title: "Focus apps", icon: "Lock", content: "Use a distraction blocker like Cold Turkey or Freedom during focused work sessions to temporarily block social media and news sites. Todoist or TickTick work well for task management with natural language date parsing and project grouping. Forest app gamifies staying off your phone by growing virtual trees during focus periods." },
  { id: "pr-05", category: "🚀 Productivity", title: "Time blocking", icon: "CalendarClock", content: "Divide your calendar into themed blocks — deep work, meetings, admin, and learning — rather than scheduling every individual task. Assign at most 3-4 blocks per day to avoid overloading yourself with context switching. Leave buffer blocks between meetings to review notes and mentally prepare for the next topic." },
  { id: "pr-06", category: "🚀 Productivity", title: "Daily planning templates", icon: "ClipboardList", content: "Write a daily plan each morning listing your top three priorities, estimated time blocks, and one non-negotiable task. Use a simple paper notebook or a digital tool like Notion with a daily template that includes goals, meetings, and reflection. End each day by writing tomorrow's plan so you start the morning with clarity." },
  { id: "pr-07", category: "🚀 Productivity", title: "Weekly review checklist", icon: "ListChecks", content: "Every Friday, review what you accomplished, what got blocked, and what needs to roll to next week. Archive or delete completed tasks and move unfinished items to next week's list with a reason for the delay. Spend 15 minutes updating documentation, cleaning up files, and organizing your workspace before the weekend." },
  { id: "pr-08", category: "🚀 Productivity", title: "Keyboard shortcuts", icon: "KeyRound", content: "Learn application-level shortcuts like Ctrl+S for save, Ctrl+Z/Y for undo/redo, and Ctrl+F for find in every tool you use. Keyboard shortcuts for your browser — Ctrl+T (new tab), Ctrl+W (close tab), Ctrl+Tab (switch tab) — compound into massive time savings. Invest 10 minutes to customize and memorize shortcuts for your most-used apps quarterly." },
  { id: "pr-09", category: "🚀 Productivity", title: "Multi-monitor setup tips", icon: "Monitor", content: "Place your primary task on the main monitor and secondary references like documentation or Slack on the side screen. Use the same monitor arrangement and orientation at home and the office so muscle memory carries over. A vertical monitor rotated to portrait mode is excellent for reading code and long documents." },
  { id: "pr-10", category: "🚀 Productivity", title: "Window management", icon: "LayoutGrid", content: "Learn your OS window-snapping shortcuts — Win+Arrow keys on Windows or Rectangle on macOS — to tile windows without reaching for the mouse. Use virtual desktops to separate workspaces by context: coding on desktop one, communication on desktop two, personal on desktop three. Dedicate one monitor or desktop space to full-screen focus mode when doing deep work." },
  { id: "pr-11", category: "🚀 Productivity", title: "File organization", icon: "FolderTree", content: "Adopt a folder structure like Projects/Client/Year/Repo to make files findable by context at a glance. Use descriptive file names with dates in ISO format (YYYY-MM-DD) so sorting chronologically works naturally. Archive or delete files older than 90 days from your downloads and desktop folders weekly." },
  { id: "pr-12", category: "🚀 Productivity", title: "Second brain techniques", icon: "Brain", content: "Build a personal knowledge base using tools like Obsidian or Notion where you store code snippets, command references, and lessons learned. Connect related notes with links or tags so your second brain grows into a web of interconnected knowledge. Review and update notes regularly — a note you never revisit is as good as one you never wrote." },
  { id: "pr-13", category: "🚀 Productivity", title: "Digital decluttering", icon: "Trash2", content: "Unsubscribe from promotional emails and mute notification-heavy Slack channels to reduce cognitive noise. Keep your desktop clean by storing files in organized folders instead of cluttering the screen with icons. Schedule a 30-minute digital declutter session every Sunday to close unused tabs, clean bookmarks, and delete old files." },
  { id: "pr-14", category: "🚀 Productivity", title: "Note-taking methods", icon: "NotebookPen", content: "The Cornell method divides notes into cues, notes, and summary sections, making review and recall much more effective. Visual note-taking with mind maps helps you grasp relationships between concepts rather than memorizing isolated facts. The Zettelkasten method focuses on creating atomic, linked notes that build on each other over time." },
  { id: "pr-15", category: "🚀 Productivity", title: "Email productivity", icon: "Mail", content: "Process email in batches two or three times a day rather than responding to every notification instantly. Use the 4D method — Delete, Delegate, Do, Defer — on each message to clear your inbox efficiently. Set up filters and labels to auto-sort newsletters, notifications, and low-priority messages away from your primary inbox." },
  { id: "pr-16", category: "🚀 Productivity", title: "Meeting efficiency", icon: "Users", content: "Always share a clear agenda and desired outcomes 24 hours before any meeting so attendees come prepared. Start and end on time — a meeting that runs long disrespects everyone's schedule and reduces focus for the rest of the day. End every meeting with a written summary of decisions made and action items with named owners." },

  // ── Student Tips ──────────────────────────────────────────────
  { id: "st-01", category: "📚 Student Tips", title: "Study techniques", icon: "GraduationCap", content: "Combine active recall (testing yourself) with spaced repetition (reviewing at increasing intervals) for the most effective long-term retention. Use the Feynman technique — explain a concept in simple language as if teaching a child — to identify gaps in your understanding. Alternate between subjects during study sessions to keep your brain engaged and improve cross-topic connections." },
  { id: "st-02", category: "📚 Student Tips", title: "Active recall", icon: "BrainCog", content: "Instead of rereading notes, close the book and write down everything you remember about a topic from memory. Use flashcards with a question on one side and the answer on the other, reviewing them in random order rather than sequentially. Practice retrieval in different environments so your recall doesn't become context-dependent." },
  { id: "st-03", category: "📚 Student Tips", title: "Spaced repetition", icon: "Repeat", content: "Use an app like Anki that schedules reviews based on how confidently you remember each card — easier cards appear less often, harder ones more frequently. Start reviewing new material one day after learning it, then extend intervals to three days, a week, a month, and beyond. Be consistent: even 10 minutes of daily review beats cramming for hours before an exam." },
  { id: "st-04", category: "📚 Student Tips", title: "Exam preparation", icon: "FileCheck", content: "Create a study plan that allocates more time to topics you find difficult and leaves the last two days for full-length mock tests under timed conditions. Focus on understanding concepts rather than memorizing answers — exams increasingly test application over recall. Get 7-8 hours of sleep the night before an exam; sleep consolidates memory more effectively than any late-night cramming session." },
  { id: "st-05", category: "📚 Student Tips", title: "Revision schedule", icon: "CalendarDays", content: "Divide your syllabus into weekly chunks at the start of the semester, assigning specific topics to specific weeks. Schedule revision sessions for previous weeks' material every Sunday to prevent forgetting before exams. Use a calendar tool or a physical planner rather than relying on memory to track your revision timeline." },
  { id: "st-06", category: "📚 Student Tips", title: "Assignment planning", icon: "ListTodo", content: "Break assignments into smaller milestones with their own deadlines: research, outline, first draft, revision, and final polish. Start your outline immediately after receiving the assignment brief so your brain can subconsciously process ideas. Aim to finish the first draft at least three days before the due date to leave ample time for revisions." },
  { id: "st-07", category: "📚 Student Tips", title: "Semester survival tips", icon: "CalendarRange", content: "Build a routine that includes fixed times for meals, exercise, and sleep alongside your study schedule to maintain physical and mental health. Stay on top of readings and assignments week by week rather than falling behind and playing catch-up before finals. Connect with classmates in each course early on so you have a support network for notes and clarifications." },
  { id: "st-08", category: "📚 Student Tips", title: "Group study hacks", icon: "UsersRound", content: "Assign clear roles for each group study session: one person explains a concept, another asks questions, a third takes notes. Teach each other topics you've already mastered — teaching reinforces your own understanding while helping your peers. Set a timer for focused discussion and another for social time to keep sessions productive." },
  { id: "st-09", category: "📚 Student Tips", title: "Research methods", icon: "Search", content: "Start your research with review articles and meta-analyses to get a broad understanding of the field before diving into primary sources. Keep a running document of citations with a sentence about why each source is relevant to avoid rereading papers later. Use reference managers like Zotero or Mendeley to organize papers and auto-generate bibliographies." },
  { id: "st-10", category: "📚 Student Tips", title: "Presentation skills", icon: "Presentation", content: "Structure your presentation with a clear hook in the first 30 seconds, three main points in the body, and a memorable takeaway at the end. Use slides as visual aids, not your script — keep text minimal and let images and diagrams carry the message. Rehearse out loud at least three times, timing each run to ensure you stay within the allotted window." },
  { id: "st-11", category: "📚 Student Tips", title: "Public speaking tips", icon: "Mic", content: "Start with a strong opening — a surprising statistic, a relevant story, or a rhetorical question — to capture attention immediately. Make eye contact with different audience members around the room rather than staring at your slides or notes. Speak slightly slower than you think you need to; nerves naturally speed up your delivery, so intentional pauses command authority." },
  { id: "st-12", category: "📚 Student Tips", title: "Memory improvement", icon: "Lightbulb", content: "Connect new information to something you already know using analogies and metaphors to create stronger neural links. Use the memory palace technique by associating facts with specific locations in a familiar route or building. Write information down by hand rather than typing — the slower process forces deeper encoding of the material." },
  { id: "st-13", category: "📚 Student Tips", title: "Reading faster", icon: "BookOpen", content: "Use a pointer or your finger to guide your eyes along each line, preventing regression and increasing reading speed by 25-50%. Preview the table of contents, headings, and summary before reading the full text to build a mental framework. Practice chunking — reading groups of 3-4 words at a glance rather than individual words — to train peripheral vision." },
  { id: "st-14", category: "📚 Student Tips", title: "Taking effective notes", icon: "PenLine", content: "Use the Cornell note-taking system: divide your page into a narrow cue column on the left and a wider notes column on the right, leaving space at the bottom for a summary. Write notes in your own words rather than transcribing the lecturer verbatim to process information actively. Review and refine your notes within 24 hours of taking them to fix gaps and reinforce learning." },
  { id: "st-15", category: "📚 Student Tips", title: "Managing deadlines", icon: "Hourglass", content: "List all deadlines at the beginning of the semester and work backward from each due date to set intermediate milestones. Use the Eisenhower Matrix — urgent vs important — to decide which task to work on when multiple deadlines converge. Communicate with your instructor early if you anticipate missing a deadline rather than waiting until after it passes." },

  // ── Career Tips ───────────────────────────────────────────────
  { id: "ca-01", category: "💼 Career Tips", title: "Resume improvements", icon: "FileText", content: "Tailor your resume for each application by matching keywords from the job description rather than sending a generic document. Quantify achievements with metrics — 'reduced load time by 40%' is far more impactful than 'improved performance.' Keep your resume to one page unless you have more than 10 years of experience, and use a clean, ATS-friendly format." },
  { id: "ca-02", category: "💼 Career Tips", title: "LinkedIn optimization", icon: "Linkedin", content: "Write a headline that goes beyond your job title — 'Frontend Engineer | React & TypeScript Specialist | Accessibility Advocate' tells a story. Post consistently about what you're learning, projects you're building, and insights from your experience to build a professional presence. Collect and display recommendations from colleagues and managers to serve as third-party validation of your skills." },
  { id: "ca-03", category: "💼 Career Tips", title: "Portfolio improvements", icon: "Briefcase", content: "Showcase live projects with clear descriptions of the problem, your approach, the tech stack, and measurable outcomes. Include a link to your GitHub and a way for visitors to contact you prominently on every page. Keep your portfolio updated with your best 3-5 projects rather than listing every experiment you've ever started." },
  { id: "ca-04", category: "💼 Career Tips", title: "GitHub profile tips", icon: "Github", content: "Pin your best repositories to the top of your profile so visitors immediately see your most impressive work. Write detailed READMEs that explain what each project does, how to run it, and what you learned building it. Contribute to open source projects and ensure your contribution history graph is green with consistent activity." },
  { id: "ca-05", category: "💼 Career Tips", title: "Interview preparation", icon: "MessageSquare", content: "Research the company's tech stack, products, and recent engineering blog posts before the interview to ask informed questions. Practice solving problems out loud while sharing your thought process — interviewers care about how you think, not just the final answer. Prepare three STAR stories (Situation, Task, Action, Result) for behavioral questions about challenges, conflicts, and failures." },
  { id: "ca-06", category: "💼 Career Tips", title: "HR interview advice", icon: "UserCheck", content: "Be prepared to answer 'Tell me about yourself' with a 60-second narrative connecting your past experience, current role, and future aspirations. Research the company culture beforehand and weave relevant values into your answers naturally. Prepare thoughtful questions about team structure, growth opportunities, and success metrics to show genuine interest." },
  { id: "ca-07", category: "💼 Career Tips", title: "Technical interview hacks", icon: "Code", content: "Start coding problems by clarifying requirements and edge cases before writing a single line of code — ask about input size, negative values, and empty inputs. Think out loud and verbalize your reasoning even if you're stuck; interviewers often give hints when they see where you're heading. Write clean, readable code with meaningful variable names even under time pressure." },
  { id: "ca-08", category: "💼 Career Tips", title: "Salary negotiation", icon: "DollarSign", content: "Research salary bands for your role, experience level, and location using sites like Levels.fyi and Glassdoor before entering negotiations. Let the employer name the first number if possible, and always respond with a researched counter-offer rather than accepting immediately. Consider total compensation including equity, bonuses, benefits, and growth opportunities, not just base salary." },
  { id: "ca-09", category: "💼 Career Tips", title: "Freelancing tips", icon: "Laptop", content: "Define your services, pricing model, and scope of work clearly in a written contract before starting any project. Build a niche expertise in a specific technology or industry rather than marketing yourself as a generalist. Deliver consistent quality and meet deadlines to earn referrals — word-of-mouth is the most effective marketing for freelancers." },
  { id: "ca-10", category: "💼 Career Tips", title: "Internship preparation", icon: "School", content: "Set specific learning goals for your internship: technologies you want to master, types of projects you want to contribute to, and people you want to learn from. Ask for regular feedback from your manager every two weeks rather than waiting for a formal mid-point review. Document your accomplishments and contributions as they happen so you have material for your resume and future interviews." },
  { id: "ca-11", category: "💼 Career Tips", title: "Networking advice", icon: "Network", content: "Focus on building genuine relationships by offering help before asking for favors — share an article, make an introduction, or give feedback on a project. Attend industry meetups, conferences, and hackathons to meet people face-to-face in a low-pressure environment. Follow up within 24 hours of meeting someone with a personalized message referencing your conversation." },
  { id: "ca-12", category: "💼 Career Tips", title: "Personal branding", icon: "Award", content: "Define what you want to be known for — a specific technical skill, a domain expertise, or a problem-solving approach — and consistently create content around that theme. Maintain a professional blog, YouTube channel, or Twitter/X presence where you share tutorials, insights, and lessons learned. Be authentic about your journey, including failures and challenges; relatable personal brands attract more engagement than polished perfection." },
  { id: "ca-13", category: "💼 Career Tips", title: "Cold emailing", icon: "Send", content: "Research the person thoroughly before reaching out — mention a specific project, article, or talk of theirs in your first sentence. Keep your email concise: who you are, why you're reaching out, and a clear, low-friction ask like a 15-minute call. Always thank them for their time regardless of their response and leave the door open for future connection." },
  { id: "ca-14", category: "💼 Career Tips", title: "Open source contributions", icon: "GitPullRequest", content: "Start by contributing to projects you already use and understand — fix a typo in docs, improve test coverage, or resolve a starter issue labeled 'good first issue.' Read the project's contributing guide and code of conduct before submitting any pull request to align with community expectations. Engage with the community on GitHub Discussions or Discord before and after submitting contributions." },
  { id: "ca-15", category: "💼 Career Tips", title: "Building credibility online", icon: "TrendingUp", content: "Write technical blog posts and tutorials that demonstrate your expertise and help others solve real problems. Speak at local meetups or virtual conferences to build authority in your area of expertise. Share your work-in-progress and lessons learned publicly on social media to build an audience even before you feel like an expert." },

  // ── Learning Hacks ────────────────────────────────────────────
  { id: "lh-01", category: "🧠 Learning Hacks", title: "Learn faster techniques", icon: "Rocket", content: "Break complex topics into smaller chunks and master each piece before moving to the next — this builds a strong mental foundation. Teach what you learn to someone else immediately, even if it's just an imaginary audience, to surface gaps in your understanding. Use interleaved practice by mixing different but related topics in a single study session to improve pattern recognition." },
  { id: "lh-02", category: "🧠 Learning Hacks", title: "How to remember concepts", icon: "MemoryStick", content: "Create memorable analogies that map new concepts to things you already understand deeply — for example, comparing a database index to a book's index. Use visual diagrams, flowcharts, and mind maps to convert abstract ideas into concrete spatial representations. Write a brief summary of what you learned in your own words immediately after studying to reinforce neural pathways." },
  { id: "lh-03", category: "🧠 Learning Hacks", title: "Best free resources", icon: "BookMarked", content: "Use freeCodeCamp, The Odin Project, and MDN Web Docs for comprehensive web development curricula with zero cost. Harvard's CS50 and MIT OpenCourseWare offer full university courses with lecture videos, assignments, and assessments. YouTube channels like Fireship, Web Dev Simplified, and Traversy Media deliver concise, high-quality tutorials on specific topics." },
  { id: "lh-04", category: "🧠 Learning Hacks", title: "Learning roadmap", icon: "Map", content: "Start by defining what you want to build or accomplish, then work backward to identify the skills you need rather than following a generic curriculum. Use roadmap.sh to visualize the technology landscape and see how different concepts connect before diving deep. Focus on 80/20 learning — the 20% of concepts that will cover 80% of real-world scenarios — rather than trying to learn everything upfront." },
  { id: "lh-05", category: "🧠 Learning Hacks", title: "Tutorial vs project learning", icon: "Route", content: "Follow one tutorial to understand the basics, then immediately build your own version of the same concept without hand-holding. The gap between following along and building from scratch is where real learning happens. Alternate between a short tutorial and a personal project repeatedly, using each project to identify what you need to learn next." },
  { id: "lh-06", category: "🧠 Learning Hacks", title: "Avoid tutorial hell", icon: "Unplug", content: "Set a strict rule: for every hour of tutorial watching, spend at least two hours building something on your own. Delete or archive tutorial projects once you finish them so you're forced to recreate the work from memory. Start a project slightly beyond your current skill level and use tutorials only as targeted references for specific problems you encounter." },
  { id: "lh-07", category: "🧠 Learning Hacks", title: "Building consistency", icon: "CheckCircle", content: "Commit to a minimum daily learning habit — even 15 minutes a day beats cramming for hours once a week. Use streak tracking and habit stacking (attach learning to an existing habit like morning coffee) to make practice automatic. Join or create a study group with regular check-ins to add social accountability to your learning routine." },
  { id: "lh-08", category: "🧠 Learning Hacks", title: "Skill stacking", icon: "Layers", content: "Combine two or more complementary skills to create a unique expertise that's more valuable than any single skill alone. For example, a developer who understands UX design or a programmer who can write technical documentation is far more versatile. Identify skills that overlap with your primary focus and learn them to a conversational level rather than mastery." },
  { id: "lh-09", category: "🧠 Learning Hacks", title: "Learning with AI", icon: "BotMessageSquare", content: "Use AI as a personalized tutor by asking it to explain concepts at different levels of depth — 'Explain this like I'm 10' through 'Explain this at a graduate level.' Ask the AI to generate practice problems with solutions you can attempt before revealing the answer. Use AI to review your code or writing and provide specific, actionable feedback rather than generic praise." },
  { id: "lh-10", category: "🧠 Learning Hacks", title: "Reading documentation", icon: "FileSearch", content: "Skim the table of contents, API reference, and a few examples before reading documentation linearly to build a mental map first. Focus on understanding the 'why' behind a function or module by reading the description and use cases rather than just the syntax. Bookmark official documentation sites and refer to them as the source of truth before consulting third-party tutorials." },
  { id: "lh-11", category: "🧠 Learning Hacks", title: "Asking better questions", icon: "CircleHelp", content: "Always include what you've already tried, what you expected to happen, and what actually happened when asking for help. Provide minimal reproduction cases — a short code snippet or steps that isolate the problem — to make it easy for others to help you. Search for existing answers on Stack Overflow, GitHub Issues, or documentation before posting your question." },
  { id: "lh-12", category: "🧠 Learning Hacks", title: "Effective Googling", icon: "Globe", content: "Use site:stackoverflow.com or site:mdn.io to limit searches to trusted sources and filter out low-quality results. Include error messages verbatim in quotes to find exact matches for your specific problem. Add terms like 'vs', 'alternative', 'best practice', or 'tutorial' depending on whether you're comparing, evaluating, or learning a new concept." },
  { id: "lh-13", category: "🧠 Learning Hacks", title: "Search operators", icon: "Filter", content: "Use the minus operator (-keyword) to exclude irrelevant results and the pipe (keyword1 | keyword2) to match either term. The filetype: operator restricts results to specific formats like filetype:pdf for documentation or filetype:md for markdown files. Combine intitle: and inurl: operators to find pages where your keywords appear in critical positions rather than anywhere on the page." },
  { id: "lh-14", category: "🧠 Learning Hacks", title: "Documentation reading tips", icon: "BookOpenCheck", content: "Start with the 'Getting Started' guide and one complete example before diving into the full API reference to establish context. Use Ctrl+F to search within documentation pages for specific terms rather than reading linearly. Focus on understanding the core concepts and 2-3 most commonly used features first, then explore advanced features as you need them." },
  { id: "lh-15", category: "🧠 Learning Hacks", title: "Reverse engineering projects", icon: "Puzzle", content: "Clone an open-source project you admire and read through its commit history to understand how it evolved from idea to production. Set breakpoints in the code and step through the execution flow to understand how different modules interact at runtime. Try to rebuild a simplified clone of a feature you use regularly — you'll learn more in a week of building than in a month of reading." },

  // ── Git & GitHub ──────────────────────────────────────────────
  { id: "gh-01", category: "🔥 Git & GitHub", title: "Commit message guide", icon: "MessageCircle", content: "Follow the Conventional Commits format: type(scope): description like feat(auth): add OAuth login. Use the imperative mood in the subject line ('Add feature' not 'Added feature') to keep commit messages consistent. Write a detailed body explaining what changed and why, especially for complex changes that might confuse future readers." },
  { id: "gh-02", category: "🔥 Git & GitHub", title: "Git branching", icon: "GitFork", content: "Use feature branches named with a pattern like feature/add-login or fix/login-error to keep the main branch stable at all times. Delete branches after merging them to keep the repository clean and avoid clutter. Rebase feature branches onto the latest main before opening a PR to avoid merge conflicts and keep history linear." },
  { id: "gh-03", category: "🔥 Git & GitHub", title: "Git stash tricks", icon: "Archive", content: "Use git stash push -m 'description' to save work with a descriptive message so you know what's in each stash. Apply a specific stash with git stash apply stash@{n} without dropping it when you need the same changes on multiple branches. Use git stash pop when you're ready to restore and remove the stash in one step." },
  { id: "gh-04", category: "🔥 Git & GitHub", title: "Cherry-pick explained", icon: "Cherry", content: "Use git cherry-pick <commit-hash> to apply a specific commit from one branch onto your current branch without merging the entire branch. Cherry-pick is perfect for hotfixes that need to be applied to multiple release branches simultaneously. Always verify the cherry-picked changes compile and pass tests since the commit may depend on context from its original branch." },
  { id: "gh-05", category: "🔥 Git & GitHub", title: "Interactive rebase", icon: "History", content: "Start an interactive rebase with git rebase -i HEAD~n to squash, reword, or reorder the last n commits before pushing. Never rebase commits that have already been pushed to a shared branch, as it rewrites history for everyone. Use fixup and autosquash during development to mark commits that should be squashed later without interrupting your flow." },
  { id: "gh-06", category: "🔥 Git & GitHub", title: "Git aliases", icon: "Waypoints", content: "Define shortcuts for your most-used commands: git config --global alias.co checkout, alias.br branch, alias.st status. Create an alias for git log --oneline --graph --decorate --all to visualize branch history at a glance. Share your alias configuration in a team dotfiles repository so everyone benefits from the same productivity boosts." },
  { id: "gh-07", category: "🔥 Git & GitHub", title: "Pull request checklist", icon: "GitPullRequestArrow", content: "Describe what the PR does, why the change is needed, and how to test it in the description so reviewers can evaluate it quickly. Keep PRs small and focused on a single concern — a PR over 400 lines is rarely reviewed thoroughly. Assign reviewers explicitly and tag them in a comment if the PR is urgent to avoid it getting lost in notifications." },
  { id: "gh-08", category: "🔥 Git & GitHub", title: "README improvements", icon: "Book", content: "Start your README with a clear project description, a screenshot or demo GIF, and badges for build status and license. Include setup instructions, prerequisites, and configuration steps so someone can run the project in under five minutes. Add a contributing section with guidelines and a code of conduct to encourage community participation." },
  { id: "gh-09", category: "🔥 Git & GitHub", title: "GitHub Actions basics", icon: "Play", content: "Start with simple workflows triggered on push and pull_request events to automate linting, testing, and building your project. Use matrix builds to test across multiple OS versions and Node.js versions in parallel without duplicating configuration. Cache dependencies with actions/cache to speed up subsequent workflow runs significantly." },
  { id: "gh-10", category: "🔥 Git & GitHub", title: "Issue templates", icon: "LayoutTemplate", content: "Provide a bug report template with fields for environment, steps to reproduce, expected behavior, and actual behavior to get actionable reports. Create a feature request template that asks for the problem being solved, proposed solution, and alternatives considered. Add a blank issue option alongside templates so contributors aren't forced into a template for every discussion." },
  { id: "gh-11", category: "🔥 Git & GitHub", title: "Release management", icon: "Tag", content: "Use GitHub Releases to tag versions with release notes, changelogs, and compiled assets alongside your source code. Follow semantic versioning (major.minor.patch) to communicate the nature of changes to users and automated systems. Automate release creation with GitHub Actions so every merged PR triggers a draft release that you can review and publish." },
  { id: "gh-12", category: "🔥 Git & GitHub", title: "Semantic versioning", icon: "Hash", content: "Use semantic versioning MAJOR.MINOR.PATCH format where MAJOR increments for breaking changes, MINOR for new features, and PATCH for bug fixes. Pre-release versions like 1.0.0-alpha.1 or 2.0.0-rc.1 signal instability to users while allowing early access. Document your versioning strategy in your README so contributors and users understand the release cycle." },

  // ── Web Development ───────────────────────────────────────────
  { id: "wd-01", category: "🌐 Web Development", title: "Website optimization", icon: "Gauge", content: "Optimize website performance by minimizing HTTP requests, compressing assets, and leveraging browser caching. Use tools like Google PageSpeed Insights and Lighthouse to identify bottlenecks. Implement critical CSS inlining and defer non-essential JavaScript for faster initial page loads." },
  { id: "wd-02", category: "🌐 Web Development", title: "SEO basics", icon: "SearchCode", content: "Improve search rankings by writing descriptive title tags and meta descriptions for every page. Use semantic HTML elements like header, nav, and main to help search engines understand your content structure. Build quality backlinks naturally by creating valuable, shareable content that others want to reference." },
  { id: "wd-03", category: "🌐 Web Development", title: "Image optimization", icon: "Image", content: "Compress images using tools like Squoosh or ImageOptim to reduce file sizes without noticeable quality loss. Use modern formats like WebP and AVIF for better compression ratios than JPEG or PNG. Serve responsive images with srcset and sizes attributes so smaller devices download appropriately sized assets." },
  { id: "wd-04", category: "🌐 Web Development", title: "Lazy loading", icon: "Loader", content: "Implement lazy loading for images and iframes using the native loading='lazy' attribute to defer off-screen resources. Use Intersection Observer API for more control over when elements should load based on viewport visibility. Lazy loading can reduce initial page weight by 30-50% on media-heavy pages." },
  { id: "wd-05", category: "🌐 Web Development", title: "Caching", icon: "HardDrive", content: "Set appropriate Cache-Control headers for static assets like CSS, JavaScript, and images to reduce server load and improve repeat visit speed. Implement ETags for efficient cache validation and version your assets with file hashes to bust caches when content changes. Use service workers for offline-first caching strategies in progressive web apps." },
  { id: "wd-06", category: "🌐 Web Development", title: "CDN basics", icon: "GlobeLock", content: "A Content Delivery Network distributes your static assets across multiple geographic servers so users download from the closest location. CDNs reduce latency, offload traffic from your origin server, and often provide DDoS protection. Major providers like Cloudflare, Fastly, and AWS CloudFront offer global edge networks with hundreds of points of presence." },
  { id: "wd-07", category: "🌐 Web Development", title: "HTTP status codes", icon: "Link", content: "Know your essential HTTP status codes: 200 for success, 201 for resource creation, 301 for permanent redirects, 404 for not found, and 500 for server errors. Use 401 for unauthorized access, 403 for forbidden resources, and 422 for validation errors in REST APIs. Proper status codes make your API more predictable and easier to debug." },
  { id: "wd-08", category: "🌐 Web Development", title: "Cookies vs Sessions", icon: "Cookie", content: "Cookies are small pieces of data stored client-side and sent with every request, making them ideal for tracking preferences but vulnerable to tampering. Sessions store data server-side with only a session ID in the cookie, offering better security for sensitive information. Use HttpOnly and Secure flags on cookies to prevent XSS attacks and ensure HTTPS-only transmission." },
  { id: "wd-09", category: "🌐 Web Development", title: "JWT explained", icon: "Key", content: "JSON Web Tokens are stateless authentication tokens consisting of a header, payload, and signature that can be verified without database lookups. Store JWTs in HttpOnly cookies rather than localStorage to prevent XSS-based token theft. Keep payload data minimal and never store sensitive information like passwords since JWTs are base64-encoded, not encrypted." },
  { id: "wd-10", category: "🌐 Web Development", title: "REST API design", icon: "ArrowLeftRight", content: "Design RESTful APIs around resources using plural nouns like /users and /orders with consistent HTTP method mapping. Use query parameters for filtering, sorting, and pagination rather than creating custom endpoints for each variation. Return consistent error responses with a standard envelope format including status, message, and error details." },
  { id: "wd-11", category: "🌐 Web Development", title: "GraphQL basics", icon: "Hexagon", content: "GraphQL lets clients request exactly the data they need in a single query, eliminating over-fetching and under-fetching common in REST APIs. Define a strong schema with types, queries, mutations, and subscriptions to create a contract between client and server. Use tools like Apollo Studio and GraphiQL to explore and test your schema during development." },
  { id: "wd-12", category: "🌐 Web Development", title: "Authentication tips", icon: "Fingerprint", content: "Always hash passwords with bcrypt or Argon2, never store them in plain text or use fast hashing algorithms like MD5 or SHA-256. Implement rate limiting on login endpoints to prevent brute force attacks and use account lockout after multiple failed attempts. Use HTTPS exclusively for all authentication endpoints to prevent credential interception." },
  { id: "wd-13", category: "🌐 Web Development", title: "Authorization patterns", icon: "ShieldAlert", content: "Implement role-based access control (RBAC) with clearly defined roles and permissions rather than hardcoding authorization logic throughout your codebase. Use middleware or decorators to enforce authorization checks at the route level before request handlers execute. Store permissions as granular scopes so you can compose them into roles flexibly." },
  { id: "wd-14", category: "🌐 Web Development", title: "Environment variables", icon: "Settings", content: "Store configuration like API keys, database URLs, and feature flags in environment variables using .env files with a library like dotenv. Never commit .env files to version control; instead commit a .env.example template with placeholder values. Validate all required environment variables at application startup with a clear error message for each missing variable." },
  { id: "wd-15", category: "🌐 Web Development", title: "Deployment checklist", icon: "CloudUpload", content: "Before deploying, run your full test suite, check for hardcoded environment-specific values, and verify that database migrations are ready. Set up health check endpoints and monitoring with alerts for error rates, response times, and resource usage. Use a blue-green deployment or canary release strategy to minimize downtime and rollback risk." },

  // ── Cybersecurity ─────────────────────────────────────────────
  { id: "cs-01", category: "🔒 Cybersecurity", title: "Strong password habits", icon: "LockKeyhole", content: "Use unique, complex passwords for every account rather than reusing the same password across multiple services. Aim for at least 12 characters combining uppercase, lowercase, numbers, and symbols for maximum security. Consider using a passphrase made of random words strung together, which is both easier to remember and harder to crack." },
  { id: "cs-02", category: "🔒 Cybersecurity", title: "Password manager tips", icon: "KeyRound", content: "A password manager like Bitwarden or 1Password generates and stores strong unique passwords for all your accounts so you only need to remember one master password. Enable two-factor authentication on your password manager account itself as an extra layer of protection. Use the built-in password generator to create random 16+ character passwords for every new account." },
  { id: "cs-03", category: "🔒 Cybersecurity", title: "Phishing detection", icon: "Fish", content: "Check the sender's email address carefully — phishing emails often use domains that look similar to legitimate ones with subtle misspellings. Hover over links before clicking to preview the actual URL destination in your browser's status bar. Be skeptical of urgent messages demanding immediate action, unexpected attachments, or requests for personal information." },
  { id: "cs-04", category: "🔒 Cybersecurity", title: "Safe browsing", icon: "Globe", content: "Keep your browser and all extensions updated to patch known security vulnerabilities attackers exploit. Use a content blocker like uBlock Origin to block malicious ads and tracking scripts that can serve malware. Enable HTTPS-only mode in your browser settings to ensure connections are always encrypted." },
  { id: "cs-05", category: "🔒 Cybersecurity", title: "HTTPS explained", icon: "Lock", content: "HTTPS encrypts all data between your browser and the server using TLS, preventing eavesdroppers from intercepting passwords, credit cards, or personal information. Look for the padlock icon in the address bar to verify a site uses HTTPS before entering sensitive data. Modern HTTPS with HSTS headers also protects against SSL stripping attacks that try to downgrade connections to HTTP." },
  { id: "cs-06", category: "🔒 Cybersecurity", title: "Two-factor authentication", icon: "Smartphone", content: "Enable two-factor authentication on every service that supports it, preferring authenticator apps like Google Authenticator or Authy over SMS-based codes. Hardware security keys like YubiKey provide the strongest form of 2FA since they're immune to phishing and SIM-swapping attacks. Backup your 2FA recovery codes in a safe place in case you lose access to your authentication device." },
  { id: "cs-07", category: "🔒 Cybersecurity", title: "Secure coding", icon: "ShieldCheck", content: "Validate and sanitize all user input on the server side to prevent injection attacks regardless of client-side validation. Use parameterized queries or prepared statements for database operations to eliminate SQL injection vulnerabilities. Apply the principle of least privilege so each component of your system has only the permissions it needs." },
  { id: "cs-08", category: "🔒 Cybersecurity", title: "API security", icon: "Shield", content: "Authenticate and authorize every API request using tokens or API keys rather than relying on IP-based access control alone. Implement rate limiting to prevent abuse and use request validation to reject malformed payloads before they reach your business logic. Log all API access with timestamps, endpoints, and user IDs for audit trails and incident investigation." },
  { id: "cs-09", category: "🔒 Cybersecurity", title: "SQL Injection prevention", icon: "Database", content: "Always use parameterized queries or prepared statements instead of concatenating user input directly into SQL strings. Use an ORM like Prisma or TypeORM that handles parameterization automatically in most cases. Apply input validation and whitelist allowed characters for fields that don't need special SQL characters." },
  { id: "cs-10", category: "🔒 Cybersecurity", title: "XSS prevention", icon: "Code", content: "Escape all user-generated content before rendering it in HTML using context-appropriate encoding for HTML, attributes, JavaScript, and CSS. Use Content Security Policy headers to restrict which scripts can execute on your page even if an XSS vulnerability exists. Framework-level protections in React and Vue auto-escape template expressions but be careful with dangerouslySetInnerHTML or v-html." },
  { id: "cs-11", category: "🔒 Cybersecurity", title: "CSRF basics", icon: "Crosshair", content: "Cross-Site Request Forgery tricks authenticated users into performing unwanted actions on a different site. Protect against CSRF by including anti-forgery tokens in forms and validating them server-side for every state-changing request. Use SameSite cookies set to Strict or Lax mode to prevent browsers from sending cookies cross-origin automatically." },
  { id: "cs-12", category: "🔒 Cybersecurity", title: "Data privacy tips", icon: "EyeOff", content: "Minimize the personal data you collect to only what's absolutely necessary for your application to function. Encrypt sensitive data both in transit with TLS and at rest using AES-256 or similar strong encryption. Provide clear privacy notices explaining what data you collect, why you need it, and how long you retain it." },
  { id: "cs-13", category: "🔒 Cybersecurity", title: "Encryption basics", icon: "Scan", content: "Symmetric encryption uses the same key for encryption and decryption, making it fast but requiring secure key sharing. Asymmetric encryption uses a public-private key pair where the public key encrypts and the private key decrypts, enabling secure communication without prior key exchange. In transit, TLS combines both approaches using asymmetric encryption to exchange a symmetric session key." },

  // ── AI Tips ───────────────────────────────────────────────────
  { id: "ai-01", category: "🤖 AI Tips", title: "Better ChatGPT prompts", icon: "MessageSquareText", content: "Treat ChatGPT like a knowledgeable collaborator by providing context, desired format, and specific constraints in your prompts. Use system-level instructions to set the role and tone before asking your actual question. Break complex requests into a series of smaller, focused prompts rather than asking everything in one message." },
  { id: "ai-02", category: "🤖 AI Tips", title: "AI workflow automation", icon: "Workflow", content: "Automate repetitive tasks like email drafting, meeting summarization, and data extraction by chaining AI calls through tools like Zapier or custom scripts. Define clear input-output templates for each automated workflow to ensure consistent results. Always review AI-generated outputs before they reach customers or stakeholders to catch hallucinations." },
  { id: "ai-03", category: "🤖 AI Tips", title: "AI coding assistants", icon: "Cpu", content: "Use GitHub Copilot or similar AI coding assistants to generate boilerplate code, write unit tests, and suggest implementations for well-understood patterns. Review AI-generated code carefully for security issues, edge cases, and correctness rather than accepting suggestions blindly. Write clear comments and function names to help the AI understand your intent and generate better suggestions." },
  { id: "ai-04", category: "🤖 AI Tips", title: "Prompt engineering", icon: "Wand", content: "Structure prompts with a clear instruction, relevant context, expected output format, and optional examples for best results. Use temperature settings — lower values for factual responses, higher values for creative tasks — to control output randomness. Iterate on prompts by analyzing failures and refining instructions based on what the model got wrong." },
  { id: "ai-05", category: "🤖 AI Tips", title: "AI for debugging", icon: "BugPlay", content: "Paste error messages and relevant code snippets to an AI and ask for potential causes and solutions specific to your stack. Describe the expected behavior versus actual behavior in detail so the AI can identify the disconnect. Use AI to generate test cases that might reproduce edge cases you haven't considered." },
  { id: "ai-06", category: "🤖 AI Tips", title: "AI for documentation", icon: "FilePen", content: "Use AI to generate initial drafts of API documentation, README files, and inline comments based on your code structure and function signatures. Review and refine AI-generated documentation to ensure accuracy and match your project's tone. Update documentation prompts as your code evolves to keep generated docs in sync with changes." },
  { id: "ai-07", category: "🤖 AI Tips", title: "AI for studying", icon: "BookOpenText", content: "Use AI to generate summaries, flashcards, and practice questions from your study materials to reinforce learning through active recall. Ask the AI to explain concepts using analogies related to topics you already understand. Request personalized study schedules that space out review sessions based on your performance on practice questions." },
  { id: "ai-08", category: "🤖 AI Tips", title: "AI research workflow", icon: "Microscope", content: "Use AI tools like Perplexity or Elicit to quickly summarize papers, extract key findings, and identify related research in your field. Have AI compare and contrast multiple sources to synthesize different perspectives on the same topic. Always verify AI-generated research summaries against original sources for accuracy and context." },
  { id: "ai-09", category: "🤖 AI Tips", title: "AI productivity stack", icon: "LayoutDashboard", content: "Build a personal AI productivity stack combining a chatbot for general queries, a writing assistant for communication, and coding tools for development tasks. Use AI note-taking tools that transcribe meetings, extract action items, and integrate with your task manager. Regularly evaluate which AI tools actually save time and drop those that create more overhead than value." },
  { id: "ai-10", category: "🤖 AI Tips", title: "AI mistakes to avoid", icon: "CircleAlert", content: "Don't rely on AI for factual accuracy without verification — models can confidently generate incorrect information (hallucinations). Avoid sharing sensitive personal or proprietary data with public AI tools that may use your inputs for training. Remember that AI lacks true understanding of context, nuance, and business logic that human experience provides." },

  // ── VS Code Tips ──────────────────────────────────────────────
  { id: "vs-01", category: "⚡ VS Code Tips", title: "Extensions worth installing", icon: "Puzzle", content: "Install essential extensions like ESLint, Prettier, GitLens, and GitHub Copilot to supercharge your development workflow. Use the Error Lens extension to see linting errors inline without hovering. The Thunder Client extension provides a lightweight Postman alternative directly inside VS Code for API testing." },
  { id: "vs-02", category: "⚡ VS Code Tips", title: "Settings.json tweaks", icon: "SlidersHorizontal", content: "Customize your VS Code settings.json with editor.formatOnSave, editor.codeActionsOnSave, and workbench.colorTheme for a personalized experience. Set editor.minimap.enabled to false if you prefer more editing space over the minimap. Use files.exclude and search.exclude to hide generated folders like node_modules from your file explorer and search results." },
  { id: "vs-03", category: "⚡ VS Code Tips", title: "Snippets", icon: "Text", content: "Create custom code snippets for repetitive patterns like React components, function templates, or console statements to save typing time each day. Use tab stops and placeholder variables with default values in your snippets to tab through customizable parts. Leverage community snippet extensions from the marketplace for popular frameworks and libraries." },
  { id: "vs-04", category: "⚡ VS Code Tips", title: "Multi-cursor tricks", icon: "MousePointerClick", content: "Press Ctrl+D to select the next occurrence of the current word, building up multiple cursors for simultaneous editing. Use Alt+Click to add cursors at arbitrary positions for editing non-contiguous areas. Ctrl+Shift+L selects all occurrences at once, perfect for renaming a variable throughout a file." },
  { id: "vs-05", category: "⚡ VS Code Tips", title: "Workspace settings", icon: "FolderCog", content: "Use workspace-level settings.json stored in a .vscode folder to enforce consistent formatting, linting, and extension recommendations across your team. Specify recommended extensions with extensions.json so team members are prompted to install them. Configure debug launch configurations for different parts of your project so anyone can start debugging with one click." },
  { id: "vs-06", category: "⚡ VS Code Tips", title: "Integrated terminal tips", icon: "Terminal", content: "Split your integrated terminal into multiple panes using Ctrl+Shift+5 to run a dev server, a build watcher, and git commands simultaneously. Use the terminal's shell integration features to navigate command output with keyboard shortcuts. Set a custom terminal font like Fira Code or Cascadia Code with ligatures for better readability." },
  { id: "vs-07", category: "⚡ VS Code Tips", title: "Debugger tips", icon: "StepForward", content: "Use conditional breakpoints that only pause execution when a specific condition is met to debug complex loops without stepping through every iteration. The Call Stack panel shows you the exact path your code took to reach the current breakpoint. Use the Watch panel to track specific variables across multiple breakpoints without adding console.log statements." },
  { id: "vs-08", category: "⚡ VS Code Tips", title: "Keyboard shortcuts", icon: "Command", content: "Master essential VS Code shortcuts: Ctrl+P for quick file search, Ctrl+Shift+P for command palette, and Ctrl+G to jump to a specific line number. Use Ctrl+B to toggle the sidebar, Ctrl+~ to toggle the terminal, and Ctrl+K Ctrl+T to change the color theme quickly. Customize any shortcut by searching for it in the Keyboard Shortcuts editor (Ctrl+K Ctrl+S)." },
  { id: "vs-09", category: "⚡ VS Code Tips", title: "Themes", icon: "Palette", content: "Choose a theme with good contrast for your lighting conditions — dark themes like One Dark Pro or Dracula work well in low light while light themes like GitHub Light are better for bright environments. Use semantic highlighting themes that color variables, functions, and types differently based on their role in the code. Set different themes for day and night using the auto-detection of Windows or macOS appearance mode." },
  { id: "vs-10", category: "⚡ VS Code Tips", title: "Hidden features", icon: "EyeOff", content: "Use Ctrl+Shift+V to preview Markdown files rendered in real-time while you edit the source. The Command Palette's 'Developer: Inspect Editor Tokens and Scopes' shows exactly which TextMate scope is applied to any character for debugging syntax highlighting. Ctrl+Shift+O lists all symbols (functions, classes, variables) in the current file with fuzzy search." },

  // ── Windows / Mac / Linux ─────────────────────────────────────
  { id: "os-01", category: "🖥️ Windows/Mac/Linux", title: "Hidden shortcuts", icon: "Keyboard", content: "Win+Shift+S on Windows opens the Snipping Tool for instant screenshots, while Cmd+Shift+5 on macOS opens similar screen capture controls. Ctrl+Shift+Escape opens Task Manager directly on Windows, bypassing the Ctrl+Alt+Del menu. On Linux, Super+Arrow keys snap windows just like Windows, and Ctrl+Alt+T opens the terminal on most distributions." },
  { id: "os-02", category: "🖥️ Windows/Mac/Linux", title: "Startup optimization", icon: "Power", content: "Disable unnecessary startup programs through Task Manager on Windows or System Preferences on macOS to significantly reduce boot time. Review and disable background services that auto-start using msconfig on Windows or launchctl on macOS. On Linux, systemd-analyze blame shows exactly which services are slowing down your boot process so you can disable the culprits." },
  { id: "os-03", category: "🖥️ Windows/Mac/Linux", title: "Disk cleanup", icon: "HardDrive", content: "Use the built-in Disk Cleanup tool on Windows or Storage Management on macOS to remove temporary files, system caches, and old updates. Tools like WinDirStat or TreeSize visualize disk usage so you can identify large files and folders taking up space. On Linux, use the du and ncdu commands to find and remove unnecessary files from your system." },
  { id: "os-04", category: "🖥️ Windows/Mac/Linux", title: "RAM optimization", icon: "Activity", content: "Close unused browser tabs and background applications to free up RAM — browsers are notorious memory hogs with dozens of open tabs. Use the Resource Monitor on Windows or Activity Monitor on macOS to identify memory-hungry processes. On Linux, use htop or the free -h command to monitor memory usage and terminate processes consuming excessive RAM." },
  { id: "os-05", category: "🖥️ Windows/Mac/Linux", title: "Clipboard managers", icon: "Clipboard", content: "Use a clipboard manager like Ditto on Windows or Maccy on macOS to access your clipboard history and paste previously copied items. Clipboard managers let you save frequently used text snippets like email addresses, code templates, and URLs for instant access. Most clipboard managers support search, favorites, and syncing across devices for seamless productivity." },
  { id: "os-06", category: "🖥️ Windows/Mac/Linux", title: "PowerToys features", icon: "Zap", content: "Microsoft PowerToys offers a suite of utilities including FancyZones for custom window layouts, PowerRename for batch file renaming, and Color Picker for grabbing colors from anywhere on screen. The PowerToys Run launcher replaces the Windows search bar with a faster, more customizable application launcher. Always Awake keeps your computer awake without changing power settings." },
  { id: "os-07", category: "🖥️ Windows/Mac/Linux", title: "Terminal tricks", icon: "TerminalSquare", content: "Use Ctrl+R for reverse search through your command history to quickly find and rerun previous commands. The !! shorthand reruns your last command prefixed with sudo if you forgot to run it as root. Use aliases in your .bashrc or .zshrc file to create shortcuts for long command sequences you use daily." },
  { id: "os-08", category: "🖥️ Windows/Mac/Linux", title: "File search shortcuts", icon: "Search", content: "On Windows, press Win+S and type the file name to search your entire system instantly, or use Everything by Voidtools for near-instantaneous file searches. Spotlight on macOS (Cmd+Space) searches files, emails, contacts, and web results from one place. On Linux, the locate command provides fast filename searches using a prebuilt database updated daily." },
  { id: "os-09", category: "🖥️ Windows/Mac/Linux", title: "Hidden settings", icon: "Settings2", content: "Windows God Mode creates a single folder containing all control panel settings by creating a new folder named 'GodMode.{ED7BA470-8E54-465E-825C-99712043E01C}'. On macOS, hold Option while clicking the volume or Wi-Fi icon to see hidden options like input and output device selection. On Linux, GNOME Tweaks and dconf-editor expose advanced settings not available in the standard Settings app." },
  { id: "os-10", category: "🖥️ Windows/Mac/Linux", title: "Battery optimization", icon: "Battery", content: "Reduce screen brightness, turn off keyboard backlighting, and disable Bluetooth when not in use to extend laptop battery life significantly. Use battery saver modes that automatically throttle performance and limit background activity when unplugged. On Windows, use the powercfg /batteryreport command to generate a detailed battery health report showing wear level and capacity history." },

  // ── DSA Tips ──────────────────────────────────────────────────
  { id: "ds-01", category: "🎯 DSA Tips", title: "Pattern recognition", icon: "Waypoints", content: "Identify common problem patterns like two pointers, sliding window, and fast-slow pointers to quickly narrow down solution strategies. Recognizing that a problem matches a known pattern lets you apply a proven approach rather than starting from scratch. Practice by categorizing each problem you solve into one of 10-15 core patterns." },
  { id: "ds-02", category: "🎯 DSA Tips", title: "Time complexity shortcuts", icon: "Clock", content: "O(n) means the algorithm scales linearly with input size, O(n²) means nested loops, and O(log n) typically indicates binary search or divide-and-conquer. Counting loop nestings is the quickest way to estimate time complexity for most algorithms. Remember that O(1) doesn't mean instant — it means constant time regardless of input size." },
  { id: "ds-03", category: "🎯 DSA Tips", title: "Space optimization", icon: "Minimize2", content: "Trade space for time when performance matters more than memory — caching, memoization, and precomputation all follow this principle. In-place algorithms modify the input data structure directly using O(1) extra space but require careful implementation to avoid data corruption. Use bit manipulation tricks to store multiple boolean flags in a single integer." },
  { id: "ds-04", category: "🎯 DSA Tips", title: "Interview roadmap", icon: "MapPin", content: "Start with arrays, strings, and hash maps to build foundation before moving to trees, graphs, and dynamic programming. Spend 30 minutes max per problem — if stuck, read the solution and come back to it the next day for spaced repetition. Focus on understanding patterns rather than memorizing specific solutions to any given problem." },
  { id: "ds-05", category: "🎯 DSA Tips", title: "Common mistakes", icon: "AlertCircle", content: "Off-by-one errors in loop boundaries are the most common DSA mistakes — always double-check your starting and ending indices. Forgetting to handle edge cases like empty arrays, single elements, or negative numbers causes many test failures. Not considering integer overflow in languages like Java or C++ when adding large numbers." },
  { id: "ds-06", category: "🎯 DSA Tips", title: "Revision strategy", icon: "RefreshCw", content: "Use spaced repetition by revisiting problems after 1 day, 3 days, 1 week, and 1 month to move solutions from short-term to long-term memory. Solve problems in timed conditions to simulate interview pressure after you understand the pattern. Keep a mistake log listing problems you couldn't solve and the key insight you missed." },
  { id: "ds-07", category: "🎯 DSA Tips", title: "Cheat sheets", icon: "ScrollText", content: "Create personal cheat sheets summarizing time and space complexity for all major data structures — array, linked list, stack, queue, hash map, tree, heap, and graph. Note down template code for common algorithms like binary search, BFS, DFS, and Dijkstra that you can adapt to specific problems. Reference your cheat sheets during practice, not during interviews." },
  { id: "ds-08", category: "🎯 DSA Tips", title: "Graph tricks", icon: "Network", content: "Use BFS for shortest path in unweighted graphs and level-order traversal, DFS for connectivity checks and topological sorting. Number of islands problems are BFS or DFS over a grid using a visited set or in-place marking. Union-Find (Disjoint Set Union) is the most efficient approach for connectivity queries in dynamic graphs." },
  { id: "ds-09", category: "🎯 DSA Tips", title: "Dynamic Programming patterns", icon: "TreePine", content: "Identify DP problems by looking for optimal substructure and overlapping subproblems where the same subproblem is solved repeatedly. Start with recursion + memoization (top-down) before attempting iterative tabulation (bottom-up) for clarity. The classic DP patterns include 0/1 KnapSack, unbounded knapSack, longest common subsequence, and palindromic subsequences." },
  { id: "ds-10", category: "🎯 DSA Tips", title: "Binary Search patterns", icon: "Binary", content: "Binary search doesn't just work on sorted arrays — apply it to any monotonic function where you need to find the boundary between true and false values. The three templates for binary search are: finding exact value, finding first true, and finding last false. Always test your binary search with input sizes of 1, 2, and 3 to catch off-by-one errors in mid calculations." },

  // ── System Design ─────────────────────────────────────────────
  { id: "sd-01", category: "🏗️ System Design", title: "Scaling basics", icon: "Maximize2", content: "Horizontal scaling adds more machines to handle load while vertical scaling upgrades existing hardware. Most modern systems favor horizontal scaling because it provides fault tolerance and near-limitless capacity. Always design stateless services first so horizontal scaling becomes trivial to implement." },
  { id: "sd-02", category: "🏗️ System Design", title: "Load balancing", icon: "Scale", content: "Load balancers distribute incoming traffic across multiple servers to prevent any single server from becoming a bottleneck. Common algorithms include round-robin, least connections, and IP hash for session persistence. Health checks are essential so the load balancer automatically stops routing traffic to failed servers." },
  { id: "sd-03", category: "🏗️ System Design", title: "Caching", icon: "DatabaseZap", content: "Caching stores frequently accessed data in fast memory to reduce database load and improve response times. Use a multi-tier cache strategy with in-memory caches like Redis at the application layer and CDN caching at the edge. Always set appropriate TTL values and have a cache invalidation strategy to prevent serving stale data." },
  { id: "sd-04", category: "🏗️ System Design", title: "Database indexing", icon: "TableProperties", content: "Database indexes work like a book's table of contents, letting the database find rows without scanning the entire table. Index columns used in WHERE, JOIN, and ORDER BY clauses but avoid over-indexing as every index slows down write operations. Use EXPLAIN to verify your queries are actually using the indexes you create." },
  { id: "sd-05", category: "🏗️ System Design", title: "Rate limiting", icon: "Gauge", content: "Rate limiting protects your APIs from abuse by capping how many requests a client can make in a given time window. Common algorithms include token bucket, leaky bucket, and sliding window log for different precision and memory trade-offs. Return 429 Too Many Requests with a Retry-After header so clients know when to try again." },
  { id: "sd-06", category: "🏗️ System Design", title: "CDN usage", icon: "Radio", content: "A CDN caches static assets like images, scripts, and stylesheets at edge servers around the world to reduce latency for users. Dynamic content can also be accelerated through CDNs with origin shielding and smart routing. Choose a CDN provider with points of presence in the regions where your users are concentrated." },
  { id: "sd-07", category: "🏗️ System Design", title: "Queues", icon: "AlignStartVertical", content: "Message queues decouple producers from consumers so services can communicate asynchronously without waiting for each other. Use queues for background jobs, event processing, and smoothing out traffic spikes where immediate responses aren't needed. Popular choices include RabbitMQ for complex routing and Amazon SQS for fully managed, serverless queueing." },
  { id: "sd-08", category: "🏗️ System Design", title: "Event-driven systems", icon: "Radio", content: "Event-driven architecture lets services react to events published on a bus rather than calling each other directly. This pattern produces loosely coupled systems where new consumers can be added without modifying existing producers. Apache Kafka excels at high-throughput event streaming while EventBridge works well for AWS-native architectures." },
  { id: "sd-09", category: "🏗️ System Design", title: "CAP theorem", icon: "Triangle", content: "The CAP theorem states a distributed system can only guarantee two of three properties: consistency, availability, and partition tolerance. Since network partitions are inevitable, you must choose between CP (consistency) and AP (availability) for each system. Databases like PostgreSQL lean CP while Cassandra and DynamoDB lean AP for different use cases." },
  { id: "sd-10", category: "🏗️ System Design", title: "Microservices tips", icon: "Boxes", content: "Design microservices around business capabilities rather than technical layers to keep each service cohesive and independently deployable. Each service should own its data store and communicate with others through well-defined APIs or events. Start with a monolith and extract services only when you have clear evidence that separation solves a real problem." },

  // ── Mobile Development ────────────────────────────────────────
  { id: "mb-01", category: "📱 Mobile Development", title: "Responsive design", icon: "Smartphone", content: "Use CSS media queries with breakpoints based on content rather than specific device sizes to future-proof your layouts. Flexible grids using relative units like rem, %, and vw/vh ensure your design adapts to any screen width. Test on real devices early in development instead of relying solely on browser DevTools emulation." },
  { id: "mb-02", category: "📱 Mobile Development", title: "Mobile-first CSS", icon: "Tablet", content: "Write base styles for mobile screens first, then add min-width media queries to enhance the layout for larger screens. This approach forces you to prioritize essential content and makes your CSS naturally smaller and more efficient. Mobile-first also aligns with progressive enhancement, ensuring your site works on any screen size." },
  { id: "mb-03", category: "📱 Mobile Development", title: "PWA tips", icon: "Download", content: "A Progressive Web App needs a service worker for offline caching and a web app manifest to control how it appears when installed. Start with a basic service worker that caches static assets, then gradually add strategies like network-first for dynamic content. Test your PWA with Lighthouse and Chrome's Application panel to verify all requirements are met." },
  { id: "mb-04", category: "📱 Mobile Development", title: "Performance optimization", icon: "Gauge", content: "Optimize images with WebP format and serve appropriately sized assets based on device resolution using srcset. Minimize JavaScript bundle size by code-splitting and lazy-loading routes that aren't immediately visible. Use tools like Lighthouse and WebPageTest to measure real-world performance on mobile network conditions." },
  { id: "mb-05", category: "📱 Mobile Development", title: "Offline support", icon: "WifiOff", content: "Implement a service worker cache-first strategy for static assets so your app loads even without an internet connection. Use IndexedDB to store user data locally and queue API requests for synchronization when connectivity returns. Show clear offline indicators in the UI so users understand what features are available versus requiring a network." },
  { id: "mb-06", category: "📱 Mobile Development", title: "Accessibility", icon: "Accessibility", content: "Ensure all touch targets are at least 44x44 pixels to accommodate thumbs and fingers on small screens. Support dynamic type so visually impaired users can increase font size without breaking your layout. Test with VoiceOver on iOS and TalkBack on Android to verify screen reader compatibility on mobile." },

  // ── UI/UX ─────────────────────────────────────────────────────
  { id: "ux-01", category: "🎨 UI/UX", title: "Color combinations", icon: "Palette", content: "Use a 60-30-10 rule for color distribution: 60% neutral primary, 30% secondary, and 10% accent for visual balance. Maintain a minimum contrast ratio of 4.5:1 for normal text and 3:1 for large text to meet WCAG accessibility standards. Stick to a curated palette of 3-5 colors rather than using every color in the rainbow." },
  { id: "ux-02", category: "🎨 UI/UX", title: "Typography rules", icon: "Type", content: "Limit your typeface choices to two complementary fonts — one for headings and one for body text — to maintain visual harmony. Set body text between 16-18px and line height between 1.5-1.75 for comfortable reading on screens. Use a modular type scale like 1.25 or 1.333 to generate consistent heading sizes from your base font." },
  { id: "ux-03", category: "🎨 UI/UX", title: "White space", icon: "Space", content: "White space (or negative space) gives content room to breathe and improves readability by visually separating different sections. Use generous padding and margins around interactive elements to reduce errors and make tapping comfortable on mobile. Resist the urge to fill every pixel — empty space signals clarity and sophistication in design." },
  { id: "ux-04", category: "🎨 UI/UX", title: "Design consistency", icon: "Layout", content: "Create a design system with reusable components, consistent spacing, and standardized colors so every screen feels like part of the same application. Define spacing in a 4px or 8px grid system to ensure visual rhythm across all breakpoints. Consistent button styles, form fields, and navigation patterns reduce the user's cognitive load and build trust." },
  { id: "ux-05", category: "🎨 UI/UX", title: "UX heuristics", icon: "Heart", content: "Jakob Nielsen's ten usability heuristics include visibility of system status, match between system and real world, and user control and freedom. Always show users where they are, what's happening, and how to undo actions to reduce frustration. Apply heuristics as a quick checklist during design reviews before investing in user testing." },
  { id: "ux-06", category: "🎨 UI/UX", title: "Component naming", icon: "Tag", content: "Name UI components based on their purpose and content rather than their visual appearance — UserCard is better than BlueRoundedBox. Use a consistent naming convention like Atomic Design (atoms, molecules, organisms) to create a shared vocabulary across your team. A well-named component library makes it obvious where to find and reuse existing patterns." },
  { id: "ux-07", category: "🎨 UI/UX", title: "Dark mode", icon: "Moon", content: "Design dark mode by inverting luminance rather than simply swapping black for white — use dark grays like #121212 instead of pure black to reduce eye strain. Ensure text contrast remains at least 4.5:1 against dark backgrounds and avoid using pure white text on pure black backgrounds. Use CSS custom properties to toggle colors globally with a single prefers-color-scheme media query." },
  { id: "ux-08", category: "🎨 UI/UX", title: "Icons usage", icon: "Frame", content: "Use icons to reinforce meaning, not replace text labels — critical actions should always include text for clarity and accessibility. Maintain consistent icon styles across your application by using a single icon set rather than mixing different libraries. SVG icons outperform icon fonts in rendering quality, accessibility, and the ability to style with CSS." },
  { id: "ux-09", category: "🎨 UI/UX", title: "Animations", icon: "Play", content: "Use animations with purpose — transitions between states, feedback on user actions, and visual hierarchy cues — rather than decorative effects. Keep animations under 300ms for functional motions and respect the prefers-reduced-motion media query to avoid causing discomfort. Easing functions like ease-in-out feel more natural than linear transitions." },
  { id: "ux-10", category: "🎨 UI/UX", title: "Accessibility", icon: "Accessibility", content: "Ensure every interactive element is reachable and operable via keyboard alone — test with Tab, Enter, Escape, and arrow keys. Use proper semantic HTML elements like button, nav, and heading tags so screen readers can navigate your content meaningfully. Write descriptive alt text for images and aria-label for icon-only buttons to provide context." },

  // ── Developer Toolbox ─────────────────────────────────────────
  { id: "tb-01", category: "🛠️ Developer Toolbox", title: "Websites every developer should know", icon: "Bookmark", content: "Bookmark MDN Web Docs for authoritative web platform documentation, Stack Overflow for community troubleshooting, and DevDocs for fast offline API lookups. GitHub Explore helps you discover trending projects while roadmap.sh guides your learning path with visual roadmaps. Keep a curated list of go-to resources organized by category so you can find answers without breaking focus." },
  { id: "tb-02", category: "🛠️ Developer Toolbox", title: "Chrome extensions", icon: "Puzzle", content: "React Developer Tools and Vue Devtools let you inspect component trees, state, and props directly in the browser. Lighthouse audits performance, accessibility, SEO, and best practices with a single click. Install a JSON formatter like JSON Viewer and a color picker like ColorZilla to speed up everyday development tasks." },
  { id: "tb-03", category: "🛠️ Developer Toolbox", title: "Browser extensions", icon: "Globe", content: "LastPass or Bitwarden manage your passwords securely across devices with autofill and password generation. uBlock Origin blocks ads and trackers while reducing page load times significantly. Add a tab suspender like OneTab to keep your browser from consuming excessive memory when working on research-heavy tasks." },
  { id: "tb-04", category: "🛠️ Developer Toolbox", title: "APIs to bookmark", icon: "Link", content: "Public APIs like GitHub, OpenWeather, and REST Countries let you prototype features with real data without building your own backend. Use Postman or Bruno to explore and test API endpoints before writing any integration code. Keep a collection of API keys and base URLs in a secure environment manager rather than hardcoding them." },
  { id: "tb-05", category: "🛠️ Developer Toolbox", title: "Mock APIs", icon: "TestTube", content: "Use JSON Server or Mock Service Worker to create realistic API responses during frontend development without a real backend. Define your data schema and routes first so frontend and backend teams can work in parallel from the same contract. Mock APIs let you simulate error states, loading delays, and edge cases that are hard to reproduce with a real server." },
  { id: "tb-06", category: "🛠️ Developer Toolbox", title: "Icons", icon: "Smile", content: "Lucide, Heroicons, and Phosphor Icons offer high-quality, open-source SVG icon sets that integrate easily with any framework. Import only the icons you use rather than entire libraries to keep bundle sizes small. Use inline SVGs instead of icon fonts for crisper rendering at any scale and better accessibility support." },
  { id: "tb-07", category: "🛠️ Developer Toolbox", title: "Fonts", icon: "Type", content: "Google Fonts, Fontsource, and Bee Fonts provide free, self-hostable typefaces with a wide range of weights and styles. Limit your project to two font families and only load the weights you actually use to minimize page load impact. Use font-display: swap in your CSS to ensure text remains visible while web fonts load." },
  { id: "tb-08", category: "🛠️ Developer Toolbox", title: "Color palettes", icon: "SwatchBook", content: "Coolors and Adobe Color generate harmonious palettes instantly using color theory principles like complementary and analogous schemes. Tailwind CSS color palettes provide a well-tested set of shades that work beautifully together out of the box. Define your palette as CSS custom properties so you can iterate on colors globally without finding every usage." },
  { id: "tb-09", category: "🛠️ Developer Toolbox", title: "Image compressors", icon: "ImageMinus", content: "Squoosh and TinyPNG reduce image file sizes by 50-80% with minimal visible quality loss using modern compression algorithms. Convert images to WebP or AVIF formats for approximately 30% smaller files than JPEG or PNG at the same quality. Automate image optimization in your build pipeline with tools like sharp or imagemin so it happens automatically on every deploy." },
  { id: "tb-10", category: "🛠️ Developer Toolbox", title: "JSON formatters", icon: "Braces", content: "Online tools like JSONLint and JSONFormatter validate and pretty-print JSON to help you spot syntax errors quickly. VS Code's built-in JSON formatter with Shift+Alt+F handles formatting without leaving your editor. For large JSON files, use jq in the terminal to slice, filter, and transform data without opening a browser." },
  { id: "tb-11", category: "🛠️ Developer Toolbox", title: "Regex testers", icon: "Regex", content: "regex101.com offers real-time matching, explanation of each regex token, and a quick reference guide for building patterns. RegExr provides a community library of tested patterns you can search and adapt for common use cases. Both tools let you test against sample text and highlight matches, captures, and errors interactively." },
  { id: "tb-12", category: "🛠️ Developer Toolbox", title: "Markdown editors", icon: "FileCode", content: "StackEdit and Dillinger are browser-based Markdown editors with live preview, making it easy to format READMEs and documentation. Obsidian and Typora provide desktop Markdown editing with WYSIWYG previews and local file management. Most code editors have built-in Markdown preview — just press Ctrl+Shift+V in VS Code to see rendered output." },

  // ── Freelancing ───────────────────────────────────────────────
  { id: "fl-01", category: "💰 Freelancing", title: "Client communication", icon: "Phone", content: "Set clear communication channels and response time expectations upfront to avoid ambiguity during the project. Provide regular progress updates even when there's nothing to report — silence makes clients anxious. Document all decisions and change requests in writing so there's always a reference point if disagreements arise." },
  { id: "fl-02", category: "💰 Freelancing", title: "Pricing strategies", icon: "Coins", content: "Charge value-based prices tied to the outcome you deliver rather than hourly rates that cap your earning potential. Research market rates for your skill level and niche, then set your price confidently without apologizing. Offer tiered packages — basic, standard, and premium — so clients self-select based on their budget and needs." },
  { id: "fl-03", category: "💰 Freelancing", title: "Proposal writing", icon: "PenTool", content: "Start proposals by restating the client's problem in your own words to show you truly understand their needs. Outline your approach, timeline, and deliverables clearly, then explain why you're uniquely qualified for this specific project. End with a clear call to action and keep proposals concise — clients skim more often than they read." },
  { id: "fl-04", category: "💰 Freelancing", title: "Contracts", icon: "Scroll", content: "Always use a written contract that covers scope, deliverables, timeline, payment terms, and intellectual property ownership. Include a kill fee or cancellation clause so you're compensated if the project ends early for reasons beyond your control. Have a lawyer review your standard contract template once rather than reinventing it for every project." },
  { id: "fl-05", category: "💰 Freelancing", title: "Invoice templates", icon: "Receipt", content: "Use tools like FreshBooks, Wave, or a simple spreadsheet template to create professional invoices with your branding and payment terms. Include invoice number, date, detailed line items, payment due date, and accepted payment methods on every invoice. Send invoices promptly at the end of each milestone or month — delayed invoicing signals that you don't prioritize getting paid." },
  { id: "fl-06", category: "💰 Freelancing", title: "Scope management", icon: "Target", content: "Define the exact scope of work in your contract and create a change request process for anything outside those boundaries. When a client asks for extras, explain how it affects the timeline and budget rather than saying yes to everything. Learn to say no politely — accommodating every request without adjustment devalues your expertise and burns you out." },
  { id: "fl-07", category: "💰 Freelancing", title: "Handling revisions", icon: "RotateCcw", content: "Include a specific number of revision rounds in your contract — typically two or three — so clients don't request unlimited changes. Structure feedback sessions by asking clients to consolidate all revisions into a single batch rather than sending them one at a time. Bill for any revisions beyond the agreed-upon rounds at your standard hourly rate." },
  { id: "fl-08", category: "💰 Freelancing", title: "Portfolio building", icon: "FolderHeart", content: "Showcase case studies that explain the problem, your process, and the measurable results you delivered rather than just screenshots of finished work. Include a mix of personal projects, client work, and contributions to open source to demonstrate breadth and initiative. Update your portfolio with your best and most recent work — a stale portfolio suggests you've stopped growing." },
  { id: "fl-09", category: "💰 Freelancing", title: "Time estimation", icon: "Timer", content: "Break projects into small tasks and estimate each one independently rather than guessing the total project time in one shot. Add a buffer of 20-30% to your raw estimates to account for unexpected complications and communication overhead. Track your actual time against estimates with tools like Toggl to calibrate your estimating skills over time." },
  { id: "fl-10", category: "💰 Freelancing", title: "Client onboarding", icon: "Handshake", content: "Create a standardized onboarding process that collects project requirements, access credentials, and stakeholder contacts in one organized document. Send a welcome packet with your contract, invoice template, communication guidelines, and project timeline so expectations are clear from day one. A smooth onboarding experience sets a professional tone and reduces confusion throughout the engagement." },

  // ── Personal Growth ───────────────────────────────────────────
  { id: "pg-01", category: "🌱 Personal Growth", title: "Building habits", icon: "Sprout", content: "Start with a habit so small it feels almost too easy — one push-up, one page read, or five minutes of focused work. Stack the new habit onto an existing routine by using the formula 'After I [current habit], I will [new habit].' Track your streaks visually and never miss twice in a row to maintain momentum without perfectionism." },
  { id: "pg-02", category: "🌱 Personal Growth", title: "Staying motivated", icon: "Flame", content: "Connect daily tasks to your deeper why — the reason you started — to push through moments of low motivation. Break overwhelming goals into small, achievable milestones so you get regular dopamine hits from completing them. Surround yourself with people who inspire and challenge you, as motivation is contagious in a supportive community." },
  { id: "pg-03", category: "🌱 Personal Growth", title: "Confidence tips", icon: "Star", content: "Build confidence by keeping a 'done list' alongside your to-do list to remind yourself of accomplishments you've already achieved. Take on small challenges outside your comfort zone regularly — each success expands your belief in your own capabilities. Stop comparing your behind-the-scenes to everyone else's highlight reel; focus on your own progress instead." },
  { id: "pg-04", category: "🌱 Personal Growth", title: "Networking", icon: "Users", content: "Focus on giving value first — share resources, make introductions, and celebrate others' successes before asking for anything. Network authentically by attending events aligned with your genuine interests rather than forcing conversations for the sake of collecting contacts. Follow up with new connections within 48 hours with a personalized message referencing what you discussed." },
  { id: "pg-05", category: "🌱 Personal Growth", title: "Communication", icon: "MessageCircle", content: "Practice active listening by summarizing what the other person said before responding — this ensures understanding and makes people feel heard. For written communication, use short paragraphs, bullet points, and bold for key information to make your messages scannable. Tailor your communication style to your audience: technical details for engineers, high-level outcomes for executives." },
  { id: "pg-06", category: "🌱 Personal Growth", title: "Reading habits", icon: "BookOpen", content: "Read 20 pages a day — that's about 30 books a year with minimal daily effort. Keep a book with you at all times or use a reading app on your phone so you can read during commute, wait times, and breaks. Take notes and highlight passages that resonate with you to retain what you read and build a personal knowledge library." },
  { id: "pg-07", category: "🌱 Personal Growth", title: "Consistency", icon: "RefreshCw", content: "Consistency beats intensity — showing up every day at 80% effort outperforms sporadic 100% effort that leads to burnout. Build systems and routines that make the right choice the easy choice rather than relying on willpower alone. Focus on the process, not the outcome, and trust that small daily actions compound into remarkable results over time." },
  { id: "pg-08", category: "🌱 Personal Growth", title: "Managing stress", icon: "Heart", content: "Practice deep breathing with the 4-7-8 method — inhale for 4 seconds, hold for 7, exhale for 8 — to activate your parasympathetic nervous system during stressful moments. Identify your stress triggers and create pre-emptive routines like morning walks or evening journaling to lower baseline anxiety. Set boundaries between work and personal life by defining shutdown rituals that signal your brain it's time to rest." },
  { id: "pg-09", category: "🌱 Personal Growth", title: "Goal setting", icon: "Target", content: "Set SMART goals — Specific, Measurable, Achievable, Relevant, and Time-bound — to turn vague aspirations into actionable plans. Write your goals down and review them weekly; the act of writing commits them to memory and reinforces your commitment. Break annual goals into quarterly objectives and monthly action items so you always know what to work on next." },
  { id: "pg-10", category: "🌱 Personal Growth", title: "Reflection techniques", icon: "CircleDot", content: "Keep a daily journal where you answer three questions: what went well, what could be better, and what I learned today. Schedule a weekly review every Sunday to assess progress toward goals, celebrate wins, and adjust plans for the coming week. Quarterly reflections help you zoom out and evaluate whether you're moving in the right direction overall." },

  // ── Micro Life Hacks ──────────────────────────────────────────
  { id: "ml-01", category: "🧩 Micro Life Hacks", title: "2-minute rule", icon: "Clock", content: "If a task takes less than two minutes, do it immediately rather than adding it to your to-do list. This rule prevents small tasks from accumulating into an overwhelming backlog that drains mental energy. Apply it to emails, file organization, quick replies, and small chores that are faster to complete than to track." },
  { id: "ml-02", category: "🧩 Micro Life Hacks", title: "5-minute planning", icon: "CalendarCheck", content: "Start each day by spending five minutes listing your top three priorities and roughly when you'll tackle them. This small planning ritual clarifies what matters most and prevents you from reacting to every notification. End the day with another five-minute review of what you accomplished and what needs to roll to tomorrow." },
  { id: "ml-03", category: "🧩 Micro Life Hacks", title: "Inbox Zero", icon: "Inbox", content: "Process every email to zero by deciding immediately: delete, delegate, respond, defer, or archive. Use filters and labels to auto-sort low-priority messages like newsletters so they never hit your primary inbox. Schedule email processing in two or three dedicated blocks per day rather than checking continuously." },
  { id: "ml-04", category: "🧩 Micro Life Hacks", title: "Browser tab management", icon: "Layout", content: "Use tab groups in Chrome or Firefox to organize related tabs by project or context, reducing visual clutter. Bookmark tabs you want to read later into a dedicated folder rather than keeping them open indefinitely. Extensions like OneTab or Tab Wrangler automatically suspend or consolidate tabs to prevent memory overload." },
  { id: "ml-05", category: "🧩 Micro Life Hacks", title: "Keyboard over mouse", icon: "Keyboard", content: "Learn keyboard shortcuts for your most-used applications and you'll save hours each week compared to mouse-dependent workflows. Master the basics first: Ctrl+C/V/X, Ctrl+Z/Y, Ctrl+F, Ctrl+S, Alt+Tab, and Win+Arrow for window management. Gradually add one or two new shortcuts per week rather than trying to memorize them all at once." },
  { id: "ml-06", category: "🧩 Micro Life Hacks", title: "Clipboard history", icon: "ClipboardList", content: "Enable clipboard history in Windows (Win+V) or use a clipboard manager like Ditto to access everything you've copied recently. Clipboard managers let you pin frequently used snippets, search through history, and paste multiple items without switching back and forth. This single tool eliminates the frustration of losing something you copied moments ago." },
  { id: "ml-07", category: "🧩 Micro Life Hacks", title: "Text expansion", icon: "Expand", content: "Use text expander tools like Espanso or Beeftext to create shortcuts that automatically expand into full sentences, code blocks, or templates. Define snippets for your email address, common replies, git commands, and frequently used code patterns to eliminate repetitive typing. Start with five snippets and expand your library as you notice yourself typing the same thing repeatedly." },
  { id: "ml-08", category: "🧩 Micro Life Hacks", title: "Smart bookmarks", icon: "Star", content: "Organize bookmarks into a logical folder hierarchy with descriptive names so you can find resources in seconds rather than minutes. Use the bookmark bar for your 5-10 most-used sites and file everything else into categorized folders. Regularly audit and prune your bookmarks — if you haven't visited a bookmark in six months, it's probably safe to delete." },
  { id: "ml-09", category: "🧩 Micro Life Hacks", title: "Automation with shortcuts", icon: "Workflow", content: "Use automation tools like AutoHotkey on Windows or Shortcuts on macOS to batch rename files, resize images, and trigger multi-step workflows with a single keystroke. Identify repetitive tasks you do daily and invest an hour to automate them — that hour pays for itself within a week. Start small by automating one simple task and gradually expand your automation library." },
  { id: "ml-10", category: "🧩 Micro Life Hacks", title: "Template reuse", icon: "Copy", content: "Create templates for emails, proposals, project briefs, and code scaffolding so you never start from scratch again. Store templates in a dedicated folder or tool like Notion where you can search, copy, and customize them in seconds. Invest in refining your templates based on past feedback — each iteration saves more time on future projects." },
]);

